import { useSelector } from 'react-redux';

const Dashboard = () => {
  const user = useSelector(state => state.auth.user);
  return (
    <div>
      <h2>Добро пожаловать, {user?.name || 'гость'}!</h2>
      <p>Роль: {user?.role || 'неизвестна'}</p>
    </div>
  );
};

export default Dashboard;
